import React, { useEffect, useState } from "react";
import image1 from "../img/image1.svg";

import "./styles.css";

export default function Home() {

  const content = [
    'Hello',
    'I AM GUSTAVO',
    'Web Developer'
  ];

  const ContentFlicker = () => {
    const [part, setPart] = useState('');
    const [i, setI] = useState(0);
    const [offset, setOffset] = useState(0);
    const [forwards, setForwards] = useState(true);
    const [skipCount, setSkipCount] = useState(0);
    const skipDelay = 15;
    const speed = 70;

    useEffect(() => {
      const intervalId = setInterval(() => {
        if (forwards) {
          if (offset >= content[i].length) {
            setSkipCount((prevSkipCount) => prevSkipCount + 1);
            if (skipCount === skipDelay) {
              setForwards(false);
              setSkipCount(0);
            }
          }
        } else {
          if (offset === 0) {
            setForwards(true);
            setI((prevI) => (prevI + 1) % content.length);
            setOffset(0);
          }
        }

        const newPart = content[i].substr(0, offset);
        setPart(newPart);

        if (skipCount === 0) {
          if (forwards) {
            setOffset((prevOffset) => prevOffset + 1);
          } else {
            setOffset((prevOffset) => prevOffset - 1);
          }
        }
      }, speed);

      return () => clearInterval(intervalId);
    }, [forwards, i, offset, skipCount]);

    return <div className="word">{part}</div>;
  };



  return (
    <div className="container">
      <div className="content">
        <div className="Hello">
          <ContentFlicker/>
        </div>
        


       
      </div>
      <img src={image1} alt="image1" />
      
    </div>
  );
}
